mapper.select:
SELECT * FROM skeleton_rag_index
WHERE style         = #{style}
  AND pose          = #{pose}
  AND template_type = #{templateType}
  AND keypoints_json_url IS NOT NULL
  AND binding_data_url   IS NOT NULL
ORDER BY user_rating DESC, hit_count DESC
LIMIT #{maxResults}

SELECT *, MATCH(prompt_summary) AGAINST (#{promptKeywords} IN BOOLEAN MODE) AS relevance
FROM skeleton_rag_index
WHERE style         = #{style}
  AND pose          = #{pose}
  AND template_type = #{templateType}
  AND keypoints_json_url IS NOT NULL
  AND binding_data_url   IS NOT NULL
  AND MATCH(prompt_summary) AGAINST (#{promptKeywords} IN BOOLEAN MODE) > 0
ORDER BY relevance DESC, user_rating DESC, hit_count DESC
LIMIT #{maxResults}
